final:
module divide_by_2 (  
    input clk,  
    input reset,  
    input [7:0] input_value,  
    output reg [7:0] output_value  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
    if (reset)  
        output_value <= 8'b0;  
    else  
        output_value <= input_value >> 1;  
end  

endmodule
